// Run in the browser DevTools console:
console.log(document.compatMode);
// Expected: "CSS1Compat"  (standards mode — DOCTYPE present and valid)
// Danger:   "BackCompat"  (quirks mode — DOCTYPE missing or malformed)

// Also inspect the html element's lang attribute:
console.log(document.documentElement.lang);  // e.g., "en" or "ar"
console.log(document.documentElement.dir);   // e.g., "ltr" or "rtl"

// Read the document language
const lang = document.documentElement.lang;  // e.g., 'en'

// Read text direction
const dir = document.documentElement.dir;    // 'ltr' | 'rtl' | ''

// Dynamically change language at runtime (e.g., after a locale switch)
document.documentElement.lang = 'fr';

// Apply a CSS class for dark mode on the root element
document.documentElement.classList.add('dark');

// Check rendering mode
if (document.compatMode !== 'CSS1Compat') {
  console.warn('Document is in quirks mode — check DOCTYPE');
}

// Get viewport dimensions (the html element is the scroll container)
const scrollTop = document.documentElement.scrollTop;
const clientHeight = document.documentElement.clientHeight;

import { Component, inject, DOCUMENT } from '@angular/core';

@Component({ selector: 'app-root', template: '' })
export class AppComponent {
  private doc = inject(DOCUMENT);

  switchLocale(lang: string, dir: 'ltr' | 'rtl'): void {
    // Safe even in SSR context
    this.doc.documentElement.lang = lang;
    this.doc.documentElement.dir = dir;
  }
}

// scripts/set-locale-lang.mjs
import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

const locales = [
  { code: 'en-US', dir: 'ltr', path: 'dist/my-app/en' },
  { code: 'fr',    dir: 'ltr', path: 'dist/my-app/fr' },
  { code: 'ar',    dir: 'rtl', path: 'dist/my-app/ar' },
];

for (const { code, dir, path } of locales) {
  const file = join(path, 'index.html');
  let html = readFileSync(file, 'utf8');
  // Replace lang attribute on the html element
  html = html.replace(
    /<html([^>]*) lang="[^"]*"([^>]*)>/,
    `<html$1 lang="${code}" dir="${dir}"$2>`
  );
  writeFileSync(file, html);
  console.log(`Updated ${file}: lang="${code}" dir="${dir}"`);
}
